+            report.errors.push(format!(
+                "baseline_hyperfine_multi.json command should invoke run_gate_bench.sh, got '{}'",
+                summary.command
+            ));
+        }
+        if summary.sample_count < 10 {
+            report.errors.push(format!(
+                "baseline_hyperfine_multi.json expected >=10 samples, got {}",
